import 'package:firebase_performance/firebase_performance.dart'; import 'package:injectable/injectable.dart'; @singleton class PerformanceService { Future<HttpMetric> startHttpTrace(String url, HttpMethod method) async { final metric = FirebasePerformance.instance.newHttpMetric(url, method); await metric.start(); return metric; } Future<Trace> startTrace(String name) async { final t = FirebasePerformance.instance.newTrace(name); await t.start(); return t; } }
